package com.tidex.mobile.meshimport android.content.Contextimport org.json.JSONArrayclass MeshMessageStore(context: Context) {    private val prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)    @Synchronized    fun isSeen(messageId: String): Boolean {        return prefs.getStringSet(KEY_SEEN_IDS, emptySet())?.contains(messageId) == true    }    @Synchronized    fun markSeen(messageId: String) {        val seen = prefs.getStringSet(KEY_SEEN_IDS, emptySet())?.toMutableSet() ?: mutableSetOf()        seen.add(messageId)        prefs.edit().putStringSet(KEY_SEEN_IDS, seen).apply()    }    @Synchronized    fun isDelivered(messageId: String): Boolean {        return prefs.getStringSet(KEY_DELIVERED_IDS, emptySet())?.contains(messageId) == true    }    @Synchronized    fun markDelivered(messageId: String) {        val delivered = prefs.getStringSet(KEY_DELIVERED_IDS, emptySet())?.toMutableSet() ?: mutableSetOf()        delivered.add(messageId)        prefs.edit().putStringSet(KEY_DELIVERED_IDS, delivered).apply()    }    @Synchronized    fun addPending(message: SOSMessage) {        val current = getPending().toMutableList()        if (current.none { it.id == message.id }) {            current.add(message)            savePending(current)        }    }    @Synchronized    fun removePending(messageId: String) {        val current = getPending().filterNot { it.id == messageId }        savePending(current)    }    @Synchronized    fun getPending(): List<SOSMessage> {        val raw = prefs.getString(KEY_PENDING_JSON, "[]") ?: "[]"        val arr = JSONArray(raw)        val items = mutableListOf<SOSMessage>()        for (i in 0 until arr.length()) {            items.add(SOSMessage.fromJsonString(arr.getJSONObject(i).toString()))        }        return items    }    private fun savePending(messages: List<SOSMessage>) {        val arr = JSONArray()        messages.forEach { arr.put(org.json.JSONObject(it.toJsonString())) }        prefs.edit().putString(KEY_PENDING_JSON, arr.toString()).apply()    }    companion object {        private const val PREFS_NAME = "tidex_mesh_store"        private const val KEY_SEEN_IDS = "seen_ids"        private const val KEY_DELIVERED_IDS = "delivered_ids"        private const val KEY_PENDING_JSON = "pending_json"    }}